self.addEventListener("push",t=>{let e;if(!t.data)return;try{e=t.data.json()}catch{e={title:"Toto ERP",body:t.data.text()}}let n={body:e.body,icon:e.icon??"/icons/icon-192x192.png",badge:e.badge??"/icons/icon-192x192.png",tag:e.tag??"toto-erp",data:{url:e.url??"/dashboard"},requireInteraction:!1,silent:!1};t.waitUntil(self.registration.showNotification(e.title,n))}),self.addEventListener("notificationclick",t=>{t.notification.close();let e=t.notification.data?.url??"/dashboard";t.waitUntil(self.clients.matchAll({type:"window",includeUncontrolled:!0}).then(t=>{for(let n of t)if("url"in n&&n.url.includes(e)&&"focus"in n)return n.focus();if(self.clients.openWindow)return self.clients.openWindow(e)}))}),self.addEventListener("pushsubscriptionchange",t=>{t.waitUntil(fetch("/api/push/vapid-key").then(t=>t.json()).then(({publicKey:t})=>self.registration.pushManager.subscribe({userVisibleOnly:!0,applicationServerKey:function(t){let e="=".repeat((4-t.length%4)%4),n=atob((t+e).replace(/-/g,"+").replace(/_/g,"/")),i=new Uint8Array(new ArrayBuffer(n.length));for(let t=0;t<n.length;t++)i[t]=n.charCodeAt(t);return i}(t)})).then(e=>fetch("/api/push/subscribe",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({subscription:e.toJSON(),oldEndpoint:t.oldSubscription?.endpoint??null})})))});